.tickets-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Top Bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    flex-wrap: wrap;
}

.search-box {
    display: flex;
    gap: 0.5rem;
}

.search-box input {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    width: 220px;
    font-size: 0.875rem;
}

.search-btn {
    padding: 0.4rem 0.75rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
}

.search-btn:hover {
    background: #0b5ed7;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.status-tabs .tab {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ced4da;
    background: white;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
    transition: all 0.15s;
}

.status-tabs .tab:hover {
    background: #e9ecef;
}

.status-tabs .tab.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.priority-filter select {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.875rem;
    background: white;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #dee2e6;
    background: #ffffff;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    padding: 1.5rem;
    background: #fdfdfd;
}

/* Ticket Cards */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #f0f4ff;
}

.ticket-card.active {
    background: #e3ecff;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.25rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    font-size: 0.9rem;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.ticket-card-footer {
    display: flex;
    align-items: center;
}

/* Status Badges */
.status-badge {
    font-size: 0.7rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-weight: 500;
    text-transform: uppercase;
}

.status-open {
    background: #d1ecf1;
    color: #0c5460;
}

.status-in-progress {
    background: #fff3cd;
    color: #856404;
}

.status-resolved {
    background: #d4edda;
    color: #155724;
}

/* Right Panel Detail */
.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    font-size: 1.1rem;
}

.detail-header h2 {
    margin: 0 0 0.5rem 0;
    font-size: 1.3rem;
}

.detail-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.status-select {
    padding: 0.3rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.85rem;
}

.priority-badge {
    padding: 0.2rem 0.6rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    color: white;
}

.detail-meta {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 1rem;
}

.detail-body {
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #eee;
}

.detail-body h3 {
    font-size: 1rem;
    margin-bottom: 0.5rem;
}

.detail-body p {
    line-height: 1.6;
    color: #333;
}

/* Comments */
.comment-section h3 {
    font-size: 1rem;
    margin-bottom: 0.75rem;
}

.comment-list {
    margin-bottom: 1rem;
}

.comment {
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.25rem;
}

.comment-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.comment-text {
    margin: 0;
    font-size: 0.9rem;
    line-height: 1.5;
}

.add-comment {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.add-comment textarea {
    padding: 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    resize: vertical;
    min-height: 80px;
    font-size: 0.875rem;
    font-family: inherit;
}

.add-comment button {
    align-self: flex-end;
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
}

.add-comment button:hover:not(:disabled) {
    background: #0b5ed7;
}

.add-comment button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    background: #f8f9fa;
    border-top: 1px solid #dee2e6;
    font-size: 0.85rem;
    color: #495057;
    text-align: center;
}

